module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);

    // Internal registers to store the 8-bit parallel output
    reg [7:0] shift_reg;

    // Counter to keep track of the number of serial inputs received
    reg [3:0] count;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset the internal registers and counter
            shift_reg <= 8'b0;
            count <= 4'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end else if (din_valid) begin
            // Shift the serial input into the shift register
            shift_reg <= {shift_reg[6:0], din_serial};
            count <= count + 1'b1;

            // Check if 8 bits have been received
            if (count == 4'b1000) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
            end else begin
                dout_valid <= 1'b0;
            end
        end else begin
            // If din_valid is not asserted, reset the dout_valid
            dout_valid <= 1'b0;
        end
    end

endmodule
